graphql.query:
query KonserTersedia {
  concerts(
    where: { available_quota: { _gt: 0 } }
    order_by: { event_date: asc }
  ) {
    id
    name
    venue
    event_date
    price
    available_quota
    artist {
      name
      genre
    }
  }
}

query CariKonser($genre: String, $keyword: String) {
  concerts(
    where: {
      _and: [
        { artist: { genre: { _eq: $genre } } }
        { name: { _ilike: $keyword } }
      ]
    }
  ) {
    id
    name
    venue
    event_date
    price
    available_quota
    artist {
      name
    }
  }
}

query DetailKonser($id: Int!) {
  concerts_by_pk(id: $id) {
    id
    name
    venue
    event_date
    price
    total_quota
    available_quota
    artist {
      id
      name
      genre
    }
  }
}

query StatistikKatalog {
  concerts_aggregate {
    aggregate {
      count
      sum {
        available_quota
      }
    }
  }
}

mutation KurangiKuota($id: Int!) {
  update_concerts(
    where: {
      id: { _eq: $id }
      available_quota: { _gt: 0 }
    }
    _inc: { available_quota: -1 }
  ) {
    affected_rows
    returning {
      id
      name
      available_quota
    }
  }
}

mutation SetKuota($id: Int!, $quota: Int!) {
  update_concerts_by_pk(
    pk_columns: { id: $id }
    _set: { available_quota: $quota }
  ) {
    id
    name
    available_quota
    total_quota
  }
}

mutation TambahKonser(
  $name: String!
  $artist_id: Int!
  $venue: String!
  $event_date: timestamptz!
  $price: numeric!
  $total_quota: Int!
  $available_quota: Int!
) {
  insert_concerts_one(
    object: {
      name: $name
      artist_id: $artist_id
      venue: $venue
      event_date: $event_date
      price: $price
      total_quota: $total_quota
      available_quota: $available_quota
    }
  ) {
    id
    name
    artist {
      name
    }
  }
}

query ArtisDenganKonser {
  artists {
    id
